import{_ as e,o as r,c as a,a5 as d}from"./chunks/framework.CW28V7p_.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Solana Learn","text":"Validator operator curriculum","tagline":"Beginner-friendly, з оригінальною Anza термінологією. Build platform для DevOps які оперують Solana валідатори.","actions":[{"theme":"brand","text":"Почати з Module 0","link":"/module-0/"},{"theme":"alt","text":"Глосарій","link":"/glossary"}]},"features":[{"title":"11 модулів від основ до операцій","details":"Module 0 (dev/sysadmin fundamentals) → 10 Solana-specific модулів. Загалом 18-22 години концентрованого вивчення."},{"title":"Hands-on на твоїх серверах","details":"Кожна секція має read-only exercises на реальних кластерах (Alpenglow, mainnet, testnet). Концепти fixуються через практику."},{"title":"Розумний quiz після кожної теми","details":"7 типів питань — MCQ, написання команд, scenario, order, diagnose, compare, explain. Mini-check після кожної секції + final quiz модуля."},{"title":"Anza docs як canonical source","details":"Кожен модуль має прямі лінки на docs.anza.xyz. Я даю beginner ramp + переклад жаргону, anza дає глибину."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1780937944000}'),n={name:"index.md"};function o(s,t,i,l,c,u){return r(),a("div",null,[...t[0]||(t[0]=[d('<h2 id="як-працює-курс" tabindex="-1">Як працює курс <a class="header-anchor" href="#як-працює-курс" aria-label="Permalink to &quot;Як працює курс&quot;">​</a></h2><ol><li><strong>Послідовно</strong> від Module 0 до Module 10. Кожен модуль будується на попередніх</li><li><strong>Hands-on exercises</strong> на твоїх реальних серверах — не пропускай, без рук концепти не fixуються</li><li><strong>Quiz після кожної секції</strong> (mini-check, 2-3 питання) і <strong>final quiz у кінці модуля</strong> (10-15 питань)</li><li><strong>Глосарій</strong> <a href="/glossary">накопичує всі терміни</a> — гортай як зустрічаєш незнайоме</li></ol><h2 id="quiz-типи-що-змусять-думати" tabindex="-1">Quiz типи що змусять думати <a class="header-anchor" href="#quiz-типи-що-змусять-думати" aria-label="Permalink to &quot;Quiz типи що змусять думати&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Тип</th><th>Як перевіряє</th></tr></thead><tbody><tr><td><strong>MCQ</strong> з smart distractors</td><td>Тонкі різниці між схожими варіантами</td></tr><tr><td><strong>Write the command</strong></td><td>Введи команду — нормалізує whitespace, перевіряє точність</td></tr><tr><td><strong>Scenario</strong></td><td>&quot;Ти білдиш Х, відбувається Y, твої next 3 кроки?&quot;</td></tr><tr><td><strong>Order the steps</strong></td><td>Перетягни кроки у правильний порядок</td></tr><tr><td><strong>Diagnose the error</strong></td><td>Лог показує помилку, що пішло не так?</td></tr><tr><td><strong>Compare &amp; contrast</strong></td><td>У чому різниця між X і Y</td></tr><tr><td><strong>Explain in your words</strong></td><td>Поясни концепт своїми словами</td></tr></tbody></table><p>Progress зберігається у localStorage браузера — можна повернутись.</p><h2 id="status-з-variant-b-expansion" tabindex="-1">Status (з Variant B expansion) <a class="header-anchor" href="#status-з-variant-b-expansion" aria-label="Permalink to &quot;Status (з Variant B expansion)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Модуль</th><th>Секцій</th><th>Status</th></tr></thead><tbody><tr><td>0. Fundamentals</td><td>9</td><td>✅ Повний (+WSL/Windows)</td></tr><tr><td>1. Solana foundations</td><td>6</td><td>✅ Повний (+Genesis ceremony)</td></tr><tr><td>2. Account model</td><td>6</td><td>✅ Повний (+PDA deep, +Token-2022)</td></tr><tr><td>3. Transactions</td><td>6</td><td>✅ Повний (+Versioned TX/ALTs, +Durable nonces)</td></tr><tr><td>4. Consensus ⭐</td><td>7</td><td>✅ Повний (+Slashing deep, +Recent SIMDs)</td></tr><tr><td>5. Networking</td><td>5</td><td>✅ Повний (+QUIC/Fiber)</td></tr><tr><td>6. Validator internals</td><td>5</td><td>✅ Повний (+Firedancer)</td></tr><tr><td>7. Stake &amp; rewards</td><td>6</td><td>✅ Повний (+Jito BE deep, +Stake split/merge)</td></tr><tr><td>8. Operations security</td><td>9</td><td>✅ Повний (+Hardware, +Kernel tuning, +Multisig, +Monitoring stack, +Runbooks)</td></tr><tr><td>9. CLI deep dive</td><td>6</td><td>✅ Повний (+Feature status, +Benchmarking)</td></tr><tr><td>10. Special topics</td><td>7</td><td>✅ Повний (+Snapshot mirror, +Compression NFTs, +Oracles)</td></tr></tbody></table><p><strong>🎓 Усі 11 модулів. 72 sections total. ~70 mini-quizzes + 11 final quizzes. ~150-term глосарій.</strong></p><p><strong>Coverage:</strong> ~95% breadth, ~90% depth of Anza docs equivalent + operational practical specifics.</p>',9)])])}const h=e(n,[["render",o]]);export{g as __pageData,h as default};
